/* BTToggleGroup styles — Figma 2864-12585.
   All colors via @btech/tokens CSS vars — no hex fallbacks. */

.bt-toggle-group {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: var(--space-sm);
}

.bt-toggle-group--small {
  gap: var(--space-xs);
}

import type { BTToggleVariant, BTToggleSize } from '../toggle/BTToggle.types';

export type { BTToggleVariant, BTToggleSize };

export interface BTToggleGroupItem<T = string> {
  /** The value associated with this item — used for selection comparison. */
  value: T;
  /** Label shown in the toggle button. */
  label: string;
  /** When true, this item is disabled regardless of group disabled state. */
  disabled?: boolean;
}

export interface BTToggleGroupProps<T = string> {
  /** List of toggle options to render. */
  items: BTToggleGroupItem<T>[];
  /** Selection mode. 'single': at most one active. 'multiple': any number. Default: 'single'. */
  type?: 'single' | 'multiple';
  /**
   * Controlled selection value.
   * - single mode: T | null
   * - multiple mode: T[]
   */
  value?: T | T[] | null;
  /** Visual style forwarded to all child toggles. Default: 'default'. */
  variant?: BTToggleVariant;
  /** Size forwarded to all child toggles. Default: 'default'. */
  size?: BTToggleSize;
  /** When true, the entire group is non-interactive. Default: false. */
  disabled?: boolean;
}
